import{_ as e,o,c as r,a2 as t}from"./chunks/framework.BWuWLRhz.js";const f=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1783349713000}'),n={name:"guide/faq.md"};function d(i,a,s,l,c,h){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="修改配置后需要重启吗" tabindex="-1">修改配置后需要重启吗？ <a class="header-anchor" href="#修改配置后需要重启吗" aria-label="Permalink to &quot;修改配置后需要重启吗？&quot;">​</a></h2><p>不需要。守护进程监视 <code>config.json</code> 的变更并在下一分钟热重载调度；启用项、阈值等非调度字段由各清理组件运行时自读，即时生效。手动改动请用原子写入（先写临时文件再覆盖）。</p><h2 id="我的设备不是-f2fs-能用吗" tabindex="-1">我的设备不是 F2FS，能用吗？ <a class="header-anchor" href="#我的设备不是-f2fs-能用吗" aria-label="Permalink to &quot;我的设备不是 F2FS，能用吗？&quot;">​</a></h2><p>可以。除 <strong>F2FS GC</strong> 外的所有功能都不依赖文件系统类型。非 F2FS 设备将 <code>gc.enabled</code> 设为 <code>false</code> 即可，其余功能照常工作。</p><h2 id="不安装-czerox-可以吗" tabindex="-1">不安装 CZeroX 可以吗？ <a class="header-anchor" href="#不安装-czerox-可以吗" aria-label="Permalink to &quot;不安装 CZeroX 可以吗？&quot;">​</a></h2><p>可以。模块会按默认 <code>config.json</code> 正常运行。CZeroX 的作用是让配置与状态查看变得直观；不安装则需手动编辑 <code>config.json</code>。</p><h2 id="支持哪些-root-方案" tabindex="-1">支持哪些 Root 方案？ <a class="header-anchor" href="#支持哪些-root-方案" aria-label="Permalink to &quot;支持哪些 Root 方案？&quot;">​</a></h2><p>Magisk、KernelSU、APatch 均可。</p><h2 id="重装模块会丢失我的设置吗" tabindex="-1">重装模块会丢失我的设置吗？ <a class="header-anchor" href="#重装模块会丢失我的设置吗" aria-label="Permalink to &quot;重装模块会丢失我的设置吗？&quot;">​</a></h2><p>安装时可选择继承旧配置，此时会沿用黑白名单与自定义路径列表；但 <code>config.json</code> 始终重置为新版默认值，需要的话重装后再调整。</p><h2 id="配置写错了会怎样" tabindex="-1">配置写错了会怎样？ <a class="header-anchor" href="#配置写错了会怎样" aria-label="Permalink to &quot;配置写错了会怎样？&quot;">​</a></h2><p>若整份 <code>config.json</code> 无法解析，守护进程会<strong>保留上一份有效任务集</strong>，不会中断服务。若只是某个任务的 <code>every</code> 非法，则<strong>仅跳过该任务</strong>的调度，其余照常。</p><h2 id="日志在哪里" tabindex="-1">日志在哪里？ <a class="header-anchor" href="#日志在哪里" aria-label="Permalink to &quot;日志在哪里？&quot;">​</a></h2><p>开启 <code>general.log</code> 后，日志位于 <code>/data/adb/modules/CZero/log/&lt;YYYY-MM-DD&gt;.log</code>，只保留当天。每条日志带来源标签，便于区分是哪个组件产生的。</p><h2 id="清理会误删我的数据吗" tabindex="-1">清理会误删我的数据吗？ <a class="header-anchor" href="#清理会误删我的数据吗" aria-label="Permalink to &quot;清理会误删我的数据吗？&quot;">​</a></h2><p>清理仅针对缓存与残留目录，并有两层保护：</p><ul><li><strong>时序屏障</strong> —— 受 <code>temporal_barrier_days</code> 约束，只处理 N 天以前的文件；如需更保守，可调大该值或缩小清理范围。</li><li><strong>回收站</strong> —— 其他 / 自定义路径清理<strong>不做真正的删除</strong>，而是先把文件移入回收站，默认保留 <strong>7 天</strong>，期间可完整恢复到原位。因此即便误删，也有挽回余地。详见<a href="/guide/features#回收站与恢复">功能详解 · 回收站与恢复</a>。</li></ul><h2 id="误删了文件怎么恢复" tabindex="-1">误删了文件怎么恢复？ <a class="header-anchor" href="#误删了文件怎么恢复" aria-label="Permalink to &quot;误删了文件怎么恢复？&quot;">​</a></h2><p>被清理的文件在回收站中保留 7 天。可在 CZeroX 中查看并恢复。</p><p>恢复会把文件原样移回原始路径（并保留原修改时间）。超过 7 天的会话会被自动清除，无法再恢复。</p><h2 id="遇到问题去哪里反馈" tabindex="-1">遇到问题去哪里反馈？ <a class="header-anchor" href="#遇到问题去哪里反馈" aria-label="Permalink to &quot;遇到问题去哪里反馈？&quot;">​</a></h2><p>请到 <a href="https://github.com/Xocio/CZero/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提交。</p>',23)])])}const p=e(n,[["render",d]]);export{f as __pageData,p as default};
